import "core-js/modules/es.array.push.js";
import AdminToggleDark from './dashboard/AdminToggleDark.vue';
import LanguageSwitcher from '@/components/LanguageSwitcher.vue';
export default {
  name: 'DashboardTabs',
  props: {
    activeTab: {
      type: String,
      default: 'dashboard'
    }
  },
  components: {
    AdminToggleDark,
    LanguageSwitcher
  },
  data() {
    return {
      isPageMenuOpen: false
    };
  },
  computed: {
    pageOptions() {
      return [{
        name: 'dashboard',
        icon: 'images',
        label: 'dashboardTabs.fileManagement'
      }, {
        name: 'customerConfig',
        icon: 'user-cog',
        label: 'dashboardTabs.userManagement'
      }, {
        name: 'systemConfig',
        icon: 'cogs',
        label: 'dashboardTabs.systemSettings'
      }, {
        name: '',
        icon: 'upload',
        label: 'dashboardTabs.fileUpload'
      }];
    },
    titleName() {
      if (this.activeTab === 'dashboard') {
        return this.$t('dashboardTabs.fileManagement');
      } else if (this.activeTab === 'customerConfig') {
        return this.$t('dashboardTabs.userManagement');
      } else if (this.activeTab === 'systemConfig') {
        return this.$t('dashboardTabs.systemSettings');
      } else {
        return this.$t('dashboardTabs.fileUpload');
      }
    },
    iconName() {
      if (this.activeTab === 'dashboard') {
        return 'images';
      } else if (this.activeTab === 'customerConfig') {
        return 'user-cog';
      } else if (this.activeTab === 'systemConfig') {
        return 'cogs';
      } else {
        return 'upload';
      }
    }
  },
  methods: {
    handleDocumentClick() {
      this.closePageMenu();
    },
    refreshDashboard() {
      location.reload();
    },
    handleTabClick(tab) {
      this.isPageMenuOpen = false;
      if (tab === this.activeTab) {
        this.refreshDashboard();
        return;
      }
      this.$router.push(`/${tab}`);
    },
    togglePageMenu() {
      this.isPageMenuOpen = !this.isPageMenuOpen;
    },
    closePageMenu() {
      this.isPageMenuOpen = false;
    }
  },
  mounted() {
    document.addEventListener('click', this.handleDocumentClick);
  },
  beforeUnmount() {
    document.removeEventListener('click', this.handleDocumentClick);
  }
};